"use client";

import { useState } from "react";
import type { CompanyEntry } from "@/lib/content";

function LogoTile({ company }: { company: CompanyEntry }) {
  const [failed, setFailed] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const initials = company.name
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0])
    .join("")
    .toUpperCase();

  return (
    <div className="rounded-[1.5rem] border border-slate-200 bg-white/92 p-4 shadow-sm shadow-slate-900/5">
      <div className="relative flex min-h-20 items-center justify-center overflow-hidden rounded-2xl border border-slate-100 bg-slate-50 px-3 py-4">
        {!loaded || failed ? (
          <div className="flex flex-col items-center justify-center">
            <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-[linear-gradient(135deg,var(--navy),var(--blue))] text-sm font-bold tracking-[0.14em] text-white shadow-lg shadow-blue-950/20">
              {initials}
            </div>
            <div className="mt-2 h-1.5 w-12 rounded-full bg-blue-100" />
          </div>
        ) : null}
        {!failed ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img
            src={`https://logo.clearbit.com/${company.domain}`}
            alt={`${company.name} logo`}
            className={`absolute inset-0 m-auto max-h-12 w-auto max-w-[78%] object-contain ${
              loaded ? "block" : "hidden"
            }`}
            loading="lazy"
            referrerPolicy="no-referrer"
            onLoad={() => setLoaded(true)}
            onError={() => setFailed(true)}
          />
        ) : null}
      </div>
      <p className="mt-3 text-center text-sm font-medium text-[var(--navy)]">
        {company.name}
      </p>
    </div>
  );
}

export function CompanyLogoGrid({
  companies,
  limit,
}: {
  companies: CompanyEntry[];
  limit?: number;
}) {
  const items = typeof limit === "number" ? companies.slice(0, limit) : companies;

  return (
    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
      {items.map((company) => (
        <LogoTile key={company.name} company={company} />
      ))}
    </div>
  );
}
